from decimal import Decimal, ROUND_HALF_UP

lines = [line.strip() for line in data.splitlines() if line.strip()]
u754_ok_amounts_decimal = []
for line in lines:
    parts = line.split()
    user = None
    amount = None
    status = None
    for part in parts:
        if part.startswith('user='):
            user = part.split('=', 1)[1]
        elif part.startswith('amount='):
            amount = part.split('=', 1)[1]
        elif part.startswith('status='):
            status = part.split('=', 1)[1]
    if user == 'u754' and status == 'ok' and amount is not None:
        u754_ok_amounts_decimal.append(Decimal(amount))

total_decimal = sum(u754_ok_amounts_decimal)
answer = float(total_decimal.quantize(Decimal('0.01'), rounding=ROUND_HALF_UP))
print(f"Count: {len(u754_ok_amounts_decimal)}, Decimal total: {total_decimal}, Rounded answer: {answer}")
